#!/usr/bin/env node
/**
 * scripts/bundle-bots.js
 *
 * Bundles telegram-bot.js and discord-bot.js with esbuild into self-contained
 * single-file scripts that require NO external node_modules at runtime.
 *
 * WHY: The default electron-builder config copied ALL of apps/web/node_modules
 * into extraResources — causing NSIS to extract thousands of small files on
 * Windows, stretching install time to 3-5 minutes. Bundling the bots means
 * their npm deps (node-telegram-bot-api, discord.js + transitive tree) are
 * compiled into ONE file each, slashing both installer size and install time.
 *
 * WHAT STAYS IN extraResources:
 *   - whatsapp-web.js + puppeteer (uses native browser automation — cannot
 *     be statically bundled; loaded lazily only when WhatsApp is enabled)
 *
 * OUTPUT:
 *   apps/web/telegram-bot.bundled.js  (~2-4 MB, fully self-contained)
 *   apps/web/discord-bot.bundled.js   (~8-12 MB, fully self-contained)
 *
 * Run automatically as part of build:win / build:mac (see package.json).
 * Safe to run multiple times — always overwrites previous output.
 */

const path  = require('path');
const fs    = require('fs');

const WEB_DIR = path.join(__dirname, '..', 'apps', 'web');

async function bundleBot(entry, outfile, externals = []) {
    const entryPath = path.join(WEB_DIR, entry);
    const outPath   = path.join(WEB_DIR, outfile);

    if (!fs.existsSync(entryPath)) {
        console.warn(`⚠  Skipping ${entry} — file not found at ${entryPath}`);
        return;
    }

    // Lazy-require esbuild so this script doesn't fail if esbuild isn't installed
    let build;
    try {
        build = require('esbuild').build;
    } catch {
        console.error('❌ esbuild not found. Run: npm install (from the project root)');
        process.exit(1);
    }

    await build({
        entryPoints: [entryPath],
        bundle:      true,
        platform:    'node',
        target:      'node18',
        outfile:     outPath,
        external:    externals,
        // Keep readable — easier to debug production issues in bot logs
        minify:      false,
        sourcemap:   false,
        logLevel:    'warning',
        // Silence the "CommonJS require() of ESM" warnings from some packages
        banner: {
            js: `// Skales bot bundle — generated by scripts/bundle-bots.js\n`,
        },
    });

    const sizeKb = Math.round(fs.statSync(outPath).size / 1024);
    console.log(`  ✓  ${entry.padEnd(22)}→  ${outfile}  (${sizeKb} KB)`);
}

async function main() {
    console.log('\n📦  Bundling bot scripts with esbuild…\n');

    // ── Telegram bot ─────────────────────────────────────────────────────────
    // node-telegram-bot-api is pure JS — bundle fully, no externals needed.
    await bundleBot('telegram-bot.js', 'telegram-bot.bundled.js');

    // ── Discord bot ──────────────────────────────────────────────────────────
    // discord.js v14 is pure JS. Optional native perf libs (erlpack, etc.)
    // are declared external so the bundle works without them — discord.js
    // falls back to pure-JS alternatives automatically when they're missing.
    await bundleBot('discord-bot.js', 'discord-bot.bundled.js', [
        'erlpack',          // optional voice perf
        'bufferutil',       // optional WS perf
        'utf-8-validate',   // optional WS perf
        'zlib-sync',        // optional compression perf
        '@discordjs/voice', // optional voice — separate opt-in package
    ]);

    // ── WhatsApp bot ─────────────────────────────────────────────────────────
    // NOT bundled: whatsapp-web.js uses puppeteer (Chromium binary + native
    // node bindings). These cannot be statically bundled. They remain in
    // extraResources/node_modules and are loaded lazily at runtime only when
    // the user enables WhatsApp integration.
    console.log(`  ℹ  whatsapp-bot.js        → shipped as-is (puppeteer native)`);

    console.log('\n✅  Bot bundling complete.\n');
}

main().catch(err => {
    console.error('❌  Bundle failed:', err.message || err);
    process.exit(1);
});
